{
  "activities": [
    {
      "type": "activity",
      "title": "Studying properties of acids and bases on reaction with indicators and metals",
      "unit_name": "Unit I: Chemical Substances - Nature and Behaviour",
      "chapter_name": "Chemical Reactions and Equations",
      "details": "Observe the reaction of HCl and NaOH with litmus solution, zinc metal, and solid sodium carbonate to understand chemical properties."
    },
    {
      "type": "activity",
      "title": "Classifying chemical reactions through observation",
      "unit_name": "Unit I: Chemical Substances - Nature and Behaviour",
      "chapter_name": "Chemical Reactions and Equations",
      "details": "Perform and observe combination, decomposition, displacement, and double displacement reactions including action of water on quicklime and heat on ferrous sulphate."
    },
    {
      "type": "activity",
      "title": "Determining reactivity series of metals",
      "unit_name": "Unit I: Chemical Substances - Nature and Behaviour",
      "chapter_name": "Metals and Non-metals",
      "details": "Observe the action of Zn, Fe, Cu, and Al on various salt solutions to arrange them in decreasing order of reactivity."
    },
    {
      "type": "activity",
      "title": "Comparing cleaning capacity of soap in soft and hard water",
      "unit_name": "Unit I: Chemical Substances - Nature and Behaviour",
      "chapter_name": "Carbon and its Compounds",
      "details": "Study the comparative cleaning capacity of a soap sample when used in soft water versus hard water."
    },
    {
      "type": "activity",
      "title": "Studying properties of acetic acid",
      "unit_name": "Unit I: Chemical Substances - Nature and Behaviour",
      "chapter_name": "Carbon and its Compounds",
      "details": "Investigate the odour, solubility in water, effect on litmus, and reaction with Sodium Hydrogen Carbonate."
    },
    {
      "type": "activity",
      "title": "Tracing path of light through a glass prism",
      "unit_name": "Unit III: Natural Phenomena",
      "chapter_name": "Natural Phenomena",
      "details": "Trace the path of a ray of light passing through a glass prism to understand refraction and dispersion."
    },
    {
      "type": "activity",
      "title": "Portfolio preparation for non-assessed topics",
      "unit_name": "Unit I, Unit II, Unit IV",
      "chapter_name": "Periodic Classification of Elements; Heredity and Evolution; Electric Effects",
      "details": "Prepare a brief write-up on Periodic Classification, Heredity and Evolution, and Electric Effects for internal assessment portfolio."
    }
  ],
  "projects": [
    {
      "title": "Scientific Inquiry Plan Design",
      "unit_name": "Unit VIII: Nature of Science by Doing Science",
      "chapter_name": "Nature of Science by Doing Science",
      "details": "Design and implement a plan for scientific inquiry including formulating hypotheses, making predictions, identifying variables, using instruments, representing data, and communicating findings."
    },
    {
      "title": "Case Study on Science in Human Life",
      "unit_name": "Unit V: Linkages between Scientific Knowledge and Other Curricular Areas",
      "chapter_name": "Linkages between Scientific Knowledge and Other Curricular Areas",
      "details": "Examine a case study related to the use of Science in human life from the perspective of Social Sciences and Ethics (e.g., Marie Curie, Jenner, green revolution, GMOs)."
    },
    {
      "title": "Simple Machines Construction",
      "unit_name": "Unit II: World of Living",
      "chapter_name": "Physical World and Scientific Principles",
      "details": "Construct simple machines (system of levers and pulleys) to demonstrate the principle of mechanical advantage."
    }
  ],
  "practicals": [
    {
      "title": "Finding pH of various samples using pH paper/universal indicator",
      "unit_name": "Unit I: Chemical Substances - Nature and Behaviour",
      "chapter_name": "Chemical Reactions and Equations",
      "details": "Determine the pH of dilute Hydrochloric Acid, Dilute NaOH solution, Dilute Ethanoic Acid solution, Lemon juice, Water, and Dilute Hydrogen Carbonate solution."
    },
    {
      "title": "Studying dependence of potential difference on current",
      "unit_name": "Unit IV: Effects of Current",
      "chapter_name": "Effects of Current",
      "details": "Study the dependence of potential difference (V) across a resistor on the current (I) passing through it, determine its resistance, and plot a graph between V and I."
    },
    {
      "title": "Determination of equivalent resistance in series and parallel",
      "unit_name": "Unit IV: Effects of Current",
      "chapter_name": "Effects of Current",
      "details": "Calculate the equivalent resistance of two resistors when connected in series and parallel."
    },
    {
      "title": "Preparing temporary mount of leaf peel to show stomata",
      "unit_name": "Unit II: World of Living",
      "chapter_name": "Life Processes",
      "details": "Prepare a temporary mount of a leaf peel to observe and identify stomata."
    },
    {
      "title": "Demonstrating CO2 release during respiration",
      "unit_name": "Unit II: World of Living",
      "chapter_name": "Life Processes",
      "details": "Experimentally show that carbon dioxide is given out during respiration."
    },
    {
      "title": "Determining focal length of optical devices",
      "unit_name": "Unit III: Natural Phenomena",
      "chapter_name": "Natural Phenomena",
      "details": "Determine the focal length of a concave mirror and a convex lens by obtaining the image of a distant object."
    },
    {
      "title": "Tracing path of light through rectangular glass slab",
      "unit_name": "Unit III: Natural Phenomena",
      "chapter_name": "Natural Phenomena",
      "details": "Trace the path of a ray of light passing through a rectangular glass slab for different angles of incidence, measuring angle of incidence, refraction, and emergence."
    },
    {
      "title": "Studying binary fission in Amoeba and budding in yeast/Hydra",
      "unit_name": "Unit II: World of Living",
      "chapter_name": "Reproduction",
      "details": "Study binary fission in Amoeba, and budding in yeast and Hydra with the help of prepared slides."
    },
    {
      "title": "Identification of embryo parts in dicot seeds",
      "unit_name": "Unit II: World of Living",
      "chapter_name": "Reproduction",
      "details": "Identify the different parts of an embryo of a dicot seed (pea, gram, or red kidney bean)."
    }
  ]
}
